import hex_md5 from "../../common/md5encrypt.js";
import { mapState, mapMutations } from "vuex";
export default {
    computed: {
        ...mapState(["hasLogin"])
    },
    onLoad() {
        uni.getProvider({
            service: "oauth",
            success: e => {
                this.providerList = e.provider.map(value => {
                    let providerName = "";
                    switch (value) {
                        case "weixin":
                            providerName = "微信登录";
                            break;
                        case "qq":
                            providerName = "QQ登录";
                            break;
                        case "sinaweibo":
                            providerName = "新浪微博登录";
                            break;
                        case "xiaomi":
                            providerName = "小米登录";
                            break;
                        case "baidu":
                            providerName = "百度登录";
                            break;
                        case "alipay":
                            providerName = "支付宝登录";
                            break;
                    }
                    return {
                        name: providerName,
                        id: value
                    };
                });
            },
            fail: e => {
                console.log("获取登录通道失败", e);
            }
        });
    },
    data() {
        return {
            logininfo: {
                loading: false,
                userCode: "",
                password: ""
            },
            providerList: [],
            acess_token: "",
            hasUserInfo: false,
            headerImg: "",
            loginImg: this.$webapi.webroot + "/Images/MP/head.png"
        };
    },
    methods: {
        ...mapMutations(["login"]),
        handleLogin: function(e) {
            console.log(e);
            this.defaultHandlerLogin();
        },
        defaultHandlerLogin: function() {
            let __this = this;
            console.log("=====================");
            __this.logininfo.loading = true;
            /* 授权 */
            uni.getUserInfo({
                provider: "weixin",
                success: function(infoRes) {
                    console.log(infoRes);
                    __this.headerImg = infoRes.userInfo.avatarUrl;
                },
                fail: err => {
                    console.log(err);
                    console.log("=============322229999999999999=============");
                }
            });
            console.log(hex_md5.hxmd5(__this.logininfo.password));

            uni.login({
                provider: __this.providerList[0].id,
                success: res => {
                    console.log("999999999999999999999999999");
                    console.log(res);
                    uni.request({
                        url: __this.$webapi.login,
                        method: "POST",
                        header: {
                            "content-type":"application/x-www-form-urlencoded;charset=utf-8",
                            Authorization: "Basic bWFnaWM6MTIzNA=="
                        },
                        data: {
                            grant_type: "password",
                            username: __this.logininfo.userCode,
                            password: hex_md5.hxmd5(__this.logininfo.password),
                          
                        },
                        success: result => {
                            if (result.statusCode != 200) {
                                uni.showToast({
                                    title: result.data.error_description,
                                    icon: "none"
                                });
								__this.logininfo.loading = false;
                                return;
                            }
                            __this.acess_token = result.data.access_token;
                            
                            console.log(result);
                            this.$store.state.userId = result.data.UserId;
                            this.$store.state.companyId = result.data.CompanyId;
                            this.$store.state.organizationCode =
                                result.data.OrganizationCode;
                            this.$store.state.userType = result.data.UserType;
                            this.$store.state.access_token =
                                result.data.access_token;
                            
                            let _this = __this;
                            result.data.ProfilePhoto = __this.headerImg;
                            this.$mbservices.setStorageInfo(
                                "JSUserInfo",
                                result.data,
                                function(result) {
                                    uni.reLaunch({
                                        url:"/pages/tabBar/firstPage/firstPage",
                                        complete: function(e) {
                                            console.log(
                                                "======================555555555555555555555555555=========================="
                                            );
                                            console.log(e);
                                        }
                                    });
                                }
                            );

                            __this.logininfo.loading = false;
                        },
                        fail: function(error) {
                            console.log("88888888888888888888888888888888888");
                            __this.logininfo.loading = false;
                            uni.showModal({
                                title: "失败:" + JSON.stringify(error)
                            });
							__this.logininfo.loading = false;
                        }
                    });
                },
                fail: err => {
                    console.log("11111111111111111111111111111111111");
                    __this.logininfo.loading = false;
                    uni.showModal({
                        title: "登录提示",
                        content: "data: '" + JSON.stringify(err) + "'",
                        showCancel: false
                    });
					__this.logininfo.loading = true;
                }
            });
        },
        BindInput: function(e) {
            console.log(e);
            var dataval = e.currentTarget.dataset.val;
            console.log(dataval);
            this.logininfo[dataval] = e.detail.value;
        },
        mpGetUserInfo(result) {
            if (result.detail.errMsg !== "getUserInfo:ok") {
                uni.showModal({
                    title: "获取用户信息失败",
                    content: "错误原因" + result.detail.errMsg,
                    showCancel: false
                });
                return;
            }
            this.hasUserInfo = true;
        },
        getAuthor(e) {}
    }
};
